2	import { clientEnv, clientSchema } from "./schema.mjs";
3	
4	const _clientEnv = clientSchema.safeParse(clientEnv);
5	
6	export const formatErrors = (
7	  /** @type {import('zod').ZodFormattedError<Map<string,string>,string>} */
8	  errors,
9	) =>
10	  Object.entries(errors)
11	    .map(([name, value]) => {
12	      if (value && "_errors" in value)
13	        return `${name}: ${value._errors.join(", ")}\n`;
14	    })
15	    .filter(Boolean);
16	
17	if (_clientEnv.success === false) {
18	  console.error(
19	    "❌ Invalid environment variables:\n",
20	    ...formatErrors(_clientEnv.error.format()),
21	  );
22	  throw new Error("Invalid environment variables");
23	}
24	
25	/**
26	 * Validate that client-side environment variables are exposed to the client.
27	 */
28	for (let key of Object.keys(_clientEnv.data)) {
29	  if (!key.startsWith("NEXT_PUBLIC_")) {
30	    console.warn("❌ Invalid public environment variable name:", key);
31	
32	    throw new Error("Invalid public environment variable name");
33	  }
34	}
35	
36	export const env = _clientEnv.data;
