```tsx
import type { NextPage } from "next";
import Head from "next/head";
import Image from "next/image";
import { signIn, signOut, useSession } from "next-auth/react";
import { trpc } from "../utils/trpc";

const ProfileShowcase: React.FC = () => {
  const { data: sessionData } = useSession();

  if (!sessionData) {
    return (
      <div className="flex flex-col items-center gap-4">
        <p className="text-2xl text-gray-700">
          Sign in to view your profile
        </p>
        <button
          className="px-4 py-2 border-2 border-blue-500 rounded-md"
          onClick={() => signIn()}
        >
          Sign in
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center gap-4">
      {sessionData.user?.image && (
        <Image
          src={sessionData.user.image}
          alt={`${sessionData.user?.name ?? "User"}'s avatar`}
          width={96}
          height={96}
          className="rounded-full"
        />
      )}
      <p className="text-2xl text-gray-700">
        Signed in as{" "}
        <span className="font-bold">{sessionData.user?.name}</span>
      </p>
      <button
        className="px-4 py-2 border-2 border-blue-500 rounded-md"
        onClick={() => signOut()}
      >
        Sign out
      </button>
    </div>
  );
};

const Profile: NextPage = () => {
  const hello = trpc.useQuery(["example.hello", { text: "from tRPC" }]);

  return (
    <>
      <Head>
        <title>Profile | Create T3 App</title>
        <meta name="description" content="Your profile" />
        <link rel="icon" href="/favicon.ico" />
      </Head>

      <main className="container mx-auto flex flex-col items-center justify-center min-h-screen p-4">
        <h1 className="text-5xl md:text-[5rem] leading-normal font-extrabold text-gray-700">
          Your <span className="text-purple-300">Profile</span>
        </h1>
        <div className="pt-6 text-2xl text-blue-500 flex justify-center items-center w-full">
          {hello.data ? <p>{hello.data.greeting}</p> : <p>Loading..</p>}
        </div>
        <div className="pt-6">
          <ProfileShowcase />
        </div>
      </main>
    </>
  );
};

export default Profile;
```

**Notes on this file:**
- `next/image` is part of Next.js core — no extra package needed.
- The avatar URL from GitHub is an `https://avatars.githubusercontent.com` URL, which must be in `next.config.mjs`'s `images.domains`. This is a documentation concern only (addressed in Step 8 below); the template itself should not configure a specific domain since it is a scaffold.
- The import path `"../utils/trpc"` is relative in exactly the same way as every other index page stub, because all stubs share the same relative position from the `/pages/` root in the final generated project.
- Conditional rendering (unauthenticated state showing a sign-in button, authenticated state showing avatar + name + sign-out button) is the exact same pattern as `AuthShowcase` in the index stub.

