        id: ctx.session.user.id,
        name: ctx.session.user.name,
        email: ctx.session.user.email,
        image: ctx.session.user.image,
      };
    },
  });
```

`ctx.session.user.id` is typed as `string` (from the `next-auth.d.ts` augmentation). `name`, `email`, and `image` are typed as `string | null | undefined` from `DefaultSession["user"]`, which is correct — GitHub does not always expose an email publicly.

